bash_commands.command:
# Find the key patterns in the entire lib directory
# 1. Object.create(null) or {__proto__: null}
grep -rl "__proto__.*null\|Object\.create(null)" /workspace/node/lib/ --include="*.js" | sort

# Now let's compile the comprehensive final list
{
  grep -rl "Object\.create(null)\|{ __proto__: null\|__proto__: null" /workspace/node/lib/ --include="*.js"
  grep -rl "ObjectHasOwn\b\|ObjectPrototypeHasOwnProperty" /workspace/node/lib/ --include="*.js"
  grep -rl "kEmptyObject\|filterOwnProperties\|setOwnProperty" /workspace/node/lib/ --include="*.js"
} | sort -u | sed 's|/workspace/node/||' | wc -l

